SELECT PROGRESS_CD
FROM STOCETDT
WHERE 1 = 1
AND GATE_CD  = #{ses.gateCd}
AND BUYER_CD = #{BUYER_CD}
AND REQ_NUM  = #{REQ_NUM}
AND REQ_SEQ  = #{REQ_SEQ}

