UPDATE STOCETDT SET
	  MOD_DATE    = SYSDATE
	, MOD_USER_ID = #{ses.userId}
	, DEL_FLAG    = CASE WHEN PROGRESS_CD = 'T' THEN '1' ELSE '0' END
	, PROGRESS_CD = CASE WHEN PROGRESS_CD = 'T' THEN PROGRESS_CD ELSE 'C' END
	, CANCEL_DATE = SYSDATE
	, CANCEL_RMK  = #{CANCEL_RMK}
WHERE 1 = 1
AND GATE_CD  = #{ses.gateCd}
AND BUYER_CD = #{BUYER_CD}
AND REQ_NUM  = #{REQ_NUM}
AND REQ_SEQ  = #{REQ_SEQ}

mapper.select:
SELECT ETHD.GATE_CD , ETHD.BUYER_CD , GETCUSTNAME(ETHD.GATE_CD, ETHD.BUYER_CD) AS BUYER_NM , ETHD.REQ_NUM , ETHD.REQ_NUM'-'ETDT.REQ_SEQ AS REQ_NUM_VIEW , ETHD.REG_DATE , ETHD.REG_USER_ID , ETHD.MOD_DATE , ETHD.MOD_USER_ID , ETHD.REQ_TYPE_CD , ETHD.REF_DOC_NO , ETHD.SUBJECT' - 'GETCUSTNAME(ETDT.GATE_CD, ETDT.ENTRST_COMP_CD) AS SUBJECT , ETHD.REQ_USER_ID , GETUSERNAME(ETHD.GATE_CD, ETHD.REQ_USER_ID, #{ses.langCd}) AS REQ_USER_NM , ETHD.REQ_USER_DEPT_CD , (ETHD.REQ_DATE, 'YYYYMMDD') AS REQ_DATE , (ETHD.CONT_DATE, 'YYYYMMDD') AS CONT_DATE , (ETHD.RCV_REQ_DATE, 'YYYYMMDD') AS RCV_REQ_DATE ,(CASE WHEN ETDT.SIGN_VALUE IS NOT NULL THEN ETDT.EFORM_ID ELSE NULL END) AS ATT_FILE_NUM ,(CASE WHEN ETDT.SIGN_VALUE IS NOT NULL THEN (SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = ETDT.GATE_CD AND UUID = ETDT.EFORM_ID AND DEL_FLAG = '0') ELSE 0 END) AS ATT_FILE_CNT , ETHD.RMKS , ETDT.REQ_SEQ , ETDT.PROGRESS_CD , ETDT.ENTRST_COMP_CD , GETCUSTNAME(ETDT.GATE_CD, ETDT.ENTRST_COMP_CD) AS ENTRST_COMP_NM , ETDT.ENTRST_OFCE_CD , GETDEPTNAME(ETDT.GATE_CD, ETDT.ENTRST_COMP_CD, ETDT.ENTRST_OFCE_CD, #{ses.langCd}) AS ENTRST_OFCE_NM , ETDT.REJECT_USER_ID ,(CASE WHEN ETDT.PROGRESS_CD = 'R' THEN (ETDT.REJECT_DATE, 'YYYY-MM-DD HH24:MI') ELSE NULL END) AS REJECT_DATE ,(CASE WHEN ETDT.PROGRESS_CD = 'R' THEN ETDT.REJECT_RMK ELSE NULL END) AS REJECT_RMK ,(CASE WHEN ETDT.PROGRESS_CD = 'C' THEN (ETDT.CANCEL_DATE, 'YYYY-MM-DD HH24:MI') ELSE NULL END) AS CANCEL_DATE ,(CASE WHEN ETDT.PROGRESS_CD = 'C' THEN ETDT.CANCEL_RMK ELSE NULL END) AS CANCEL_RMK , ETDT.SIGN_USER_ID , GETUSERNAME(ETDT.GATE_CD, ETDT.SIGN_USER_ID, #{ses.langCd}) AS SIGN_USER_NM ,(CASE WHEN ETDT.PROGRESS_CD = 'E' THEN (ETDT.SIGN_DATE, 'YYYY-MM-DD HH24:MI') ELSE NULL END) AS SIGN_DATE , ETDT.EFORM_ID , ETDT.APP_STATUS , ETDT.APP_DATE FROM STOCETHD ETHD INNER JOIN STOCETDT ETDT ON (ETHD.GATE_CD = ETDT.GATE_CD AND ETHD.BUYER_CD = ETDT.BUYER_CD AND ETHD.REQ_NUM = ETDT.REQ_NUM AND ETDT.DEL_FLAG = '0') WHERE 1 = 1 AND ETHD.GATE_CD = #{ses.gateCd} AND ETHD.DEL_FLAG = '0' AND ETDT.ENTRST_COMP_CD = #{ses.companyCd}
AND ETHD.REQ_DATE BETWEEN (#{REQ_DATE_FROM}) AND (#{REQ_DATE_TO})
AND ETHD.SUBJECT LIKE '%' UPPER(#{SUBJECT}) '%'
AND ETDT.PROGRESS_CD IN
#{item}
ORDER BY ETDT.REQ_NUM DESC, ETDT.REQ_SEQ

