INSERT INTO STOCETHD (
	GATE_CD
	, BUYER_CD
	, REQ_NUM
	, REG_DATE
	, REG_USER_ID
	, DEL_FLAG
	, PROGRESS_CD
	, REQ_TYPE_CD
	, REF_DOC_NO
	, SUBJECT
	, CONTENTS_CLOB
	, REQ_USER_ID
	, REQ_USER_DEPT_CD
	, REQ_USER_EMAIL
	, REQ_USER_CELL_NUM
	, REQ_USER_TEL_NUM
	, REQ_DATE
	, CONT_DATE
	, RCV_REQ_DATE
	, ATT_FILE_NUM
	, RMKS
	, ATT_CONTENTS
) VALUES (
	#{ses.gateCd}
	, #{ses.companyCd}
	, #{REQ_NUM}
	, SYSDATE
	, #{ses.userId}
	, '0'
	, #{PROGRESS_CD}
	, #{REQ_TYPE_CD}
	, #{REF_DOC_NO}
	, #{SUBJECT}
	, #{CONTENTS_CLOB}
	, #{REQ_USER_ID}
	, #{REQ_USER_DEPT_CD}
	, #{REQ_USER_EMAIL}
	, #{REQ_USER_CELL_NUM}
	, #{REQ_USER_TEL_NUM}
	, SYSDATE
	, #{CONT_DATE}
	, #{RCV_REQ_DATE}
	, #{ATT_FILE_NUM}
	, #{RMKS}
	, #{ATT_CONTENTS}
)

