SELECT ETHD.GATE_CD , ETHD.REQ_NUM , ETHD.REG_DATE , ETHD.REG_USER_ID , ETHD.MOD_DATE , ETHD.MOD_USER_ID , ETHD.BUYER_CD , GETCOMPANYNAME(ETHD.GATE_CD, ETHD.BUYER_CD, #{ses.langCd}) ' ' GETDEPTNAME(ETHD.GATE_CD, ETHD.BUYER_CD, ETHD.REQ_USER_DEPT_CD, #{ses.langCd}) AS BUYER_NM , ETHD.REQ_TYPE_CD , ETHD.REF_DOC_NO , ETHD.SUBJECT , ETHD.CONTENTS_CLOB , ETHD.REQ_USER_ID , GETUSERNAME(ETHD.GATE_CD, ETHD.REQ_USER_ID, #{ses.langCd}) AS REQ_USER_NM , ETHD.REQ_USER_DEPT_CD , GETDEPTNAME(ETHD.GATE_CD, ETHD.BUYER_CD, ETHD.REQ_USER_DEPT_CD, #{ses.langCd}) AS REQ_USER_DEPT_NM , ETHD.REQ_USER_TEL_NUM AS REQ_USER_TEL_NUM , (ETHD.REQ_DATE, 'YYYYMMDD') AS REQ_DATE , (ETHD.CONT_DATE, 'YYYYMMDD') AS CONT_DATE , (ETHD.RCV_REQ_DATE, 'YYYYMMDD') AS RCV_REQ_DATE , ETHD.ATT_FILE_NUM , (SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = ETHD.GATE_CD AND UUID = ETHD.ATT_FILE_NUM AND DEL_FLAG = '0') AS ATT_FILE_CNT , ETHD.RMKS , ETHD.ATT_CONTENTS , ETDT.REQ_SEQ , ETDT.PROGRESS_CD ,(SELECT IRS_NUM FROM STOCCUST WHERE GATE_CD = ETDT.GATE_CD AND CUST_CD = ETDT.ENTRST_COMP_CD) AS ENTRST_IRS_NO , ETDT.ENTRST_COMP_CD , GETCUSTNAME(ETDT.GATE_CD, ETDT.ENTRST_COMP_CD) AS ENTRST_COMP_NM , ETDT.ENTRST_OFCE_CD , GETDEPTNAME(ETDT.GATE_CD, ETDT.ENTRST_COMP_CD, ETDT.ENTRST_OFCE_CD, #{ses.langCd}) AS ENTRST_OFCE_NM , ETDT.REJECT_USER_ID ,(CASE WHEN ETDT.PROGRESS_CD = 'R' THEN (ETDT.REJECT_DATE, 'YYYY-MM-DD HH24:MI') ELSE NULL END) AS REJECT_DATE ,(CASE WHEN ETDT.PROGRESS_CD = 'R' THEN ETDT.REJECT_RMK ELSE NULL END) AS REJECT_RMK , ETDT.SIGN_USER_ID , (ETDT.SIGN_DATE, 'YYYY-MM-DD HH24:MI') AS SIGN_DATE , ETDT.EFORM_ID , ETDT.APP_DOC_NUM , ETDT.APP_DOC_CNT , ETDT.APP_STATUS , ETDT.APP_DATE FROM STOCETHD ETHD INNER JOIN STOCETDT ETDT ON (ETHD.GATE_CD = ETDT.GATE_CD AND ETHD.BUYER_CD = ETDT.BUYER_CD AND ETHD.REQ_NUM = ETDT.REQ_NUM AND ETDT.DEL_FLAG = '0') WHERE 1 = 1 AND ETHD.GATE_CD = #{ses.gateCd}
AND ETHD.BUYER_CD = #{BUYER_CD} AND ETHD.REQ_NUM = #{REQ_NUM} AND ETDT.REQ_SEQ = #{REQ_SEQ}
AND ETDT.ENTRST_COMP_CD = #{BUYER_CD} AND ETDT.APP_DOC_NUM = #{APP_DOC_NUM}
AND ETHD.DEL_FLAG = '0'

