UPDATE STOCETDT SET
	  MOD_DATE    = SYSDATE
	, MOD_USER_ID = #{ses.userId}
	, EFORM_ID    = #{UUID}
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND REQ_NUM  = #{REQ_NUM}
  AND REQ_SEQ  = #{REQ_SEQ}

UPDATE STOCETDT SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , APP_STATUS  = #{SIGN_STATUS}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND REQ_NUM  = #{REQ_NUM}
   AND REQ_SEQ  = #{REQ_SEQ}

        UPDATE STOCETDT
		   SET APP_DOC_NUM = #{APP_DOC_NUM}
             , APP_DOC_CNT = CASE WHEN #{APP_DOC_CNT} = '' THEN NULL ELSE #{APP_DOC_CNT} END
         WHERE GATE_CD  = #{ses.gateCd}
           AND BUYER_CD = #{BUYER_CD}
           AND REQ_NUM  = #{REQ_NUM}
           AND REQ_SEQ  = #{REQ_SEQ}

