	  MOD_DATE     = SYSDATE
	, MOD_USER_ID  = #{ses.userId}
	, PROGRESS_CD  = 'E'
	, SIGN_USER_ID = #{ses.userId}
	, SIGN_DATE    = SYSDATE
	, SIGN_VALUE   = #{SIGN_VALUE}
	, VID_RANDOM   = #{VID_RANDOM}
WHERE 1 = 1
  AND GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND REQ_NUM  = #{REQ_NUM}
  AND REQ_SEQ  = #{REQ_SEQ}

